def nota_textual(nota):
    """
       float -> str
       OBJ: retorna el equivalente textual a una calificación numérica
       PRE: 0 <= nota <=10
    """
    if 0 <= nota < 5:
        nota_texto = "Suspenso"
    elif 5 <= nota <= 6.5:
        nota_texto = "Aprobado"
    elif 6.5 < nota <= 8.5:
        nota_texto = "Notable"
    else:
        nota_texto = "Sobresaliente"
    return nota_texto

