def burbuja3(lista):
    """ lista -> None
    OBJ: Ordena ascendentemente por bubble sort
    """
    n = len(lista)
    for i in range(n):
        intercambio = False
        for j in range(0, n-i-1):
            if lista[j] > lista[j+1]:
                lista[j], lista[j+1] = lista[j+1], lista[j]
                intercambio = True
        if not intercambio: break

E140.solution:
def burbuja(lista):
    """ lista -> None
    OBJ: Ordena la lista ascendentemente, método burbuja
    """
    for pasada in range(len(lista)-1, 0, -1):
        for i in range(pasada):
            if lista[i] > lista[i+1]:
                lista[i], lista[i+1] = lista[i+1], lista[i]

